    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True, args=['--no-sandbox'])
        page = await browser.new_page()

        await page.goto('https://www.zhcw.com/kjxx/qlc/', timeout=60000)
        await page.wait_for_load_state('networkidle', timeout=30000)

        # 获取页面中所有的JavaScript变量和数据
        print("🔍 分析页面中的JavaScript数据...")

        data = await page.evaluate('''async () => {
            const result = {
                // 查找Vue实例
                vueData: [],
                // 查找所有data属性
                allDataAttrs: [],
                // 查找表格数据
                tableData: [],
                // 查找API URL
                apiUrls: []
            };

            // 查找Vue实例
            const vueElements = document.querySelectorAll('[v-for], [v-data], [v-bind]');
            for (let el of vueElements) {
                if (el.__vue__) {
                    result.vueData.push({
                        text: el.textContent?.substring(0, 100),
                        data: el.__vue__.$data ? JSON.stringify(el.__vue__.$data).substring(0, 500) : 'no data'
                    });
                }
            }

            // 查找表格数据
            const tables = document.querySelectorAll('table');
            for (let table of tables) {
                const rows = table.querySelectorAll('tr');
                const rowsData = [];
                for (let row of rows) {
                    const cells = row.querySelectorAll('td, th');
                    if (cells.length > 0) {
                        rowsData.push({
                            cellCount: cells.length,
                            firstCell: cells[0]?.textContent?.substring(0, 20)
                        });
                    }
                }
                result.tableData.push({
                    rowCount: rows.length,
                    sample: rowsData.slice(0, 5)
                });
            }

            // 查找script标签中的数据
            const scripts = document.querySelectorAll('script');
            for (let script of scripts) {
                const content = script.textContent;
                if (content && content.includes('qh') && content.includes('kjsj')) {
                    result.apiUrls.push({
                        length: content.length,
                        sample: content.substring(0, 500)
                    });
                }
            }

            return result;
        }''')

        print("📊 页面分析结果:")
        print(json.dumps(data, ensure_ascii=False, indent=2))

        await browser.close()

asyncio.run(analyze_page())
