import asyncio
import json
from playwright.async_api import async_playwright

async def use_api():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True, args=['--no-sandbox'])
        page = await browser.new_page()

        # 启用网络拦截
        client = await page.context.new_cdp_session(page)
        await client.send('Network.enable')

        api_calls = []

        # 监听网络请求
        def handle_request(request):
            if 'qlc' in request.url.lower() or 'kjxx' in request.url:
                api_calls.append({
                    'url': request.url,
                    'method': request.method,
                    'post_data': request.post_data
                })

        page.on('request', handle_request)

        print("📡 访问中彩网，监听API调用...")
        await page.goto('https://www.zhcw.com/kjxx/qlc/', timeout=60000)
        await page.wait_for_load_state('networkidle', timeout=30000)

        # 点击"近100期"
        await page.evaluate('''() => {
            const elements = document.querySelectorAll('*');
            for (let el of elements) {
                if (el.textContent && el.textContent.includes('近100期') && el.click) {
                    el.click();
                    return;
                }
            }
        }''')

        await page.wait_for_timeout(3000)

        # 点击"自定义查询"
        await page.evaluate('''() => {
            const elements = document.querySelectorAll('*');
            for (let el of elements) {
                if (el.textContent && el.textContent.includes('自定义查询') && el.click) {
                    el.click();
                    return;
                }
            }
        }''')

        await page.wait_for_timeout(3000)

        print(f"\n📡 发现的API调用:")
        for call in api_calls:
            print(f"  - {call['method']} {call['url']}")

        await browser.close()

asyncio.run(use_api())
