#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
七乐彩数据爬虫 - 直接分析页面结构版
"""

import asyncio
import json
from playwright.async_api import async_playwright
from datetime import datetime

async def analyze_and_scrape():
    all_data = []

    async with async_playwright() as p:
        browser = await p.chromium.launch(
            headless=False,
            args=['--no-sandbox']
        )

        context = await browser.new_context(
            viewport={'width': 1280, 'height': 900},
            user_agent='Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        )

        page = await context.new_page()

        print("🚀 访问中彩网...")
        await page.goto('https://www.zhcw.com/kjxx/qlc/')
        await page.wait_for_load_state('networkidle', timeout=60000)
        print("✅ 页面加载完成")

        # 分析页面结构
        print("\n🔍 分析页面结构...")

        structure = await page.evaluate('''() => {
            const result = {
                hasTable: false,
                tableRows: 0,
                hasCustomQuery: false,
                dialogVisible: false,
                inputs: [],
                buttons: [],
                vueData: null
            };

            // 检查表格
            const table = document.querySelector('table');
            if (table) {
                result.hasTable = true;
                result.tableRows = table.querySelectorAll('tr').length;
            }

            // 检查自定义查询
            const allElements = document.querySelectorAll('*');
            for (let el of allElements) {
                if (el.textContent && el.textContent.includes('自定义查询')) {
                    result.hasCustomQuery = true;
                    break;
                }
            }

            // 检查dialog
            const dialogs = document.querySelectorAll('[class*="dialog"], [class*="modal"], [class*="popup"]');
            result.dialogVisible = dialogs.length > 0;

            // 收集输入框
            const inputs = document.querySelectorAll('input');
            for (let inp of inputs) {
                result.inputs.push({
                    type: inp.type,
                    placeholder: inp.placeholder,
                    visible: inp.offsetParent !== null,
                    disabled: inp.disabled
                });
            }

            // 收集按钮
            const buttons = document.querySelectorAll('button');
            for (let btn of buttons) {
                result.buttons.push({
                    text: btn.textContent?.substring(0, 30),
                    visible: btn.offsetParent !== null
                });
            }

            // 查找Vue实例数据
            try {
                const vueEl = document.querySelector('[class*="el-dialog"]') || document.querySelector('.ivu-modal');
                if (vueEl && vueEl.__vue__) {
                    result.vueData = JSON.stringify(vueEl.__vue__.$data).substring(0, 500);
                }
            } catch(e) {}

            return result;
        }''')

        print(f"\n📊 页面分析结果:")
        print(f"   表格: {structure['hasTable']}, 行数: {structure['tableRows']}")
        print(f"   自定义查询: {structure['hasCustomQuery']}")
        print(f"   对话框: {structure['dialogVisible']}")
        print(f"   输入框数量: {len(structure['inputs'])}")
        for i, inp in enumerate(structure['inputs'][:5]):
            print(f"     [{i}] type={inp['type']}, placeholder='{inp['placeholder']}', visible={inp['visible']}")
        print(f"   按钮数量: {len(structure['buttons'])}")
        for i, btn in enumerate(structure['buttons'][:5]):
            print(f"     [{i}] text='{btn['text']}', visible={btn['visible']}")

        # 点击自定义查询
        print("\n🔘 点击'自定义查询'...")
        await page.evaluate('''() => {
            const elements = document.querySelectorAll('*');
            for (let el of elements) {
                if (el.textContent && el.textContent.includes('自定义查询') && el.click) {
                    el.click();
                    return;
                }
            }
        }''')
        await page.wait_for_timeout(3000)

        # 再次分析页面
        print("\n🔍 再次分析页面（点击后）...")
        structure2 = await page.evaluate('''() => {
            const result = {
                dialogVisible: false,
                inputs: [],
                buttons: []
            };

            // 检查dialog
            const dialogs = document.querySelectorAll('[class*="dialog"], [class*="modal"], [class*="popup"]');
            result.dialogVisible = dialogs.length > 0;

            // 收集输入框
            const inputs = document.querySelectorAll('input');
            for (let inp of inputs) {
                result.inputs.push({
                    type: inp.type,
                    placeholder: inp.placeholder,
                    visible: inp.offsetParent !== null,
                    value: inp.value
                });
            }

            // 收集按钮
            const buttons = document.querySelectorAll('button');
            for (let btn of buttons) {
                const text = btn.textContent?.trim();
                if (text) {
                    result.buttons.push({
                        text: text,
                        visible: btn.offsetParent !== null
                    });
                }
            }

            return result;
        }''')

        print(f"   对话框: {structure2['dialogVisible']}")
        print(f"   输入框数量: {len(structure2['inputs'])}")
        for i, inp in enumerate(structure2['inputs']):
            if inp['visible']:
                print(f"     [{i}] type={inp['type']}, placeholder='{inp['placeholder']}', value='{inp['value']}'")
        print(f"   按钮: {len(structure2['buttons'])}")
        for btn in structure2['buttons'][:10]:
            if btn['visible']:
                print(f"     - {btn['text']}")

        await page.screenshot(path='/home/lang/.openclaw/workspace/caipiao/analyze.png')

        await browser.close()

    return all_data

async def main():
    print("=" * 60)
    print("🔍 七乐彩页面结构分析")
    print("=" * 60)

    await analyze_and_scrape()

if __name__ == '__main__':
    asyncio.run(main())

#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
七乐彩数据爬虫 - 深入分析版
"""

import asyncio
import json
from playwright.async_api import async_playwright
from datetime import datetime

async def deep_analyze():
    async with async_playwright() as p:
        browser = await p.chromium.launch(
            headless=False,
            args=['--no-sandbox']
        )

        context = await browser.new_context(
            viewport={'width': 1280, 'height': 900},
            user_agent='Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        )

        page = await context.new_page()

        print("🚀 访问页面...")
        await page.goto('https://www.zhcw.com/kjxx/qlc/')
        await page.wait_for_load_state('networkidle', timeout=60000)

        # 深入分析
        print("\n🔍 深度分析页面...")

        result = await page.evaluate('''() => {
            const info = {
                scripts: [],
                iframes: [],
                modals: [],
                forms: [],
                links: []
            };

            // 检查脚本中的数据
            const scripts = document.querySelectorAll('script');
            for (let script of scripts) {
                const content = script.textContent;
                if (content && content.includes('qh') && content.includes('kjsj')) {
                    info.scripts.push({
                        length: content.length,
                        sample: content.substring(0, 1000)
                    });
                }
            }

            // 检查iframe
            const iframes = document.querySelectorAll('iframe');
            for (let iframe of iframes) {
                info.iframes.push({
                    src: iframe.src,
                    visible: iframe.offsetParent !== null
                });
            }

            // 检查弹窗/模态框
            const modals = document.querySelectorAll('[class*="modal"], [class*="dialog"], [class*="popup"]');
            for (let modal of modals) {
                info.modals.push({
                    className: modal.className,
                    visible: modal.offsetParent !== null,
                    display: window.getComputedStyle(modal).display,
                    opacity: window.getComputedStyle(modal).opacity
                });
            }

            // 检查表单
            const forms = document.querySelectorAll('form');
            for (let form of forms) {
                info.forms.push({
                    action: form.action,
                    method: form.method
                });
            }

            // 检查所有链接
            const links = document.querySelectorAll('a');
            for (let link of links) {
                const text = link.textContent?.trim();
                if (text && (text.includes('查询') || text.includes('期'))) {
                    info.links.push({
                        text: text.substring(0, 30),
                        href: link.href,
                        visible: link.offsetParent !== null
                    });
                }
            }

            return info;
        }''')

        print(f"\n📊 深度分析结果:")
        print(f"   相关脚本: {len(result['scripts'])}")
        for i, script in enumerate(result['scripts'][:2]):
            print(f"     [{i}] 长度: {script['length']}")
            print(f"         样本: {script['sample'][:200]}...")

        print(f"   Iframes: {len(result['iframes'])}")
        for iframe in result['iframes']:
            print(f"     src: {iframe['src'][:50]}..., visible: {iframe['visible']}")

        print(f"   弹窗/对话框: {len(result['modals'])}")
        for modal in result['modals'][:5]:
            print(f"     class: {modal['className'][:50]}...")
            print(f"     visible: {modal['visible']}, display: {modal['display']}, opacity: {modal['opacity']}")

        print(f"   表单: {len(result['forms'])}")
        for form in result['forms']:
            print(f"     action: {form['action']}, method: {form['method']}")

        print(f"   相关链接: {len(result['links'])}")
        for link in result['links'][:10]:
            if link['visible']:
                print(f"     - {link['text']}: {link['href'][:50]}...")

        await page.screenshot(path='/home/lang/.openclaw/workspace/caipiao/deep_analyze.png')

        await browser.close()

async def main():
    print("=" * 60)
    print("🔍 深度分析中彩网页面结构")
    print("=" * 60)

    await deep_analyze()

if __name__ == '__main__':
    asyncio.run(main())

