async def get_history():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page()

        url = "https://www.17500.cn/widget/qlc/kjlist.html"
        print(f"访问: {url}")

        await page.goto(url, timeout=60000)
        await page.wait_for_load_state('networkidle', timeout=30000)

        # 获取页面内容
        html = await page.content()
        print(f"页面长度: {len(html)} 字符")

        # 查找数据
        data = await page.evaluate('''() => {
            const result = [];
            // 查找所有tr
            const trs = document.querySelectorAll('tr');
            trs.forEach(tr => {
                const cells = tr.querySelectorAll('td, th');
                if (cells.length >= 3) {
                    const period = cells[0]?.innerText?.trim() || '';
                    if (period.match(/^20\\d{6}$/)) {
                        // 提取号码
                        let numbers = cells[2]?.innerText?.trim() || '';
                        numbers = numbers.replace(/\\s+/g, ' ').replace(/\\n/g, ' ').trim();

                        result.push({
                            period: period,
                            date: cells[1]?.innerText?.trim() || '',
                            numbers: numbers,
                        });
                    }
                }
            });
            return result;
        }''')

        print(f"\\n✅ 获取到 {len(data)} 条数据")

        if len(data) > 0:
            print(f"数据范围: {data[-1]['period']} - {data[0]['period']}")
            print(f"\\n前5条:")
            for item in data[:5]:
                print(f"  {item['period']}: {item['numbers']}")

        await browser.close()

asyncio.run(get_history())
