        # 获取页面内容并保存
        html = await page.content()
        with open('/tmp/kjlist.html', 'w') as f:
            f.write(html)
        print(f"页面已保存到 /tmp/kjlist.html ({len(html)} 字符)")

        # 查找包含期号的行
        rows = await page.evaluate('''() => {
            const result = [];
            const trs = document.querySelectorAll('tr');
            trs.forEach((tr, i) => {
                const text = tr.innerText || '';
                if (text.match(/20\\d{6}/)) {
                    result.push({index: i, text: text.substring(0, 100)});
                }
            });
            return result;
        }''')

        print(f"\\n找到 {len(rows)} 行包含期号")
        for r in rows[:5]:
            print(f"  Row {r['index']}: {r['text']}")

        await browser.close()

asyncio.run(debug())
